76				ApiKeyID:  uuid.UUID(row.ApikeyID.Bytes).String(),
77				Suffix:    row.PlainSuffix,
78				CreatedAt: row.CreatedAt.Time.UTC().Format(time.RFC3339),
79				ExpiredAt: formatExpiredAt(row.ExpiredAt),
80			})
81		}
82	
83		_ = json.NewEncoder(w).Encode(ListApiKeysResponse{ApiKeys: items})
84	}
