for (const r of rows) {
  const has = r.content.includes('## 理解度チェック');
  const m = r.content.match(/## 理解度チェック\n\n([\s\S]*)/);
  const lines = m ? m[1].split('\n').filter(l => l.trim().startsWith('-')).length : 0;
  console.log((has ? 'has' : 'no').padEnd(4), String(lines).padStart(2), '|', r.title);
}
await sql.end();
"

